mapper.select:
        select
id, user_id, amount, status,description, order_time, is_deleted, create_user, update_user, create_time, update_time
        from `order`

        1 = 1 and is_deleted = 0

                and id = #{id}


                and user_id = #{userId}


                and amount = #{amount}


                and status = #{status}


                and order_time = #{orderTime}


                and is_deleted = #{isDeleted}


                and create_user = #{createUser}


                and update_user = #{updateUser}


                and create_time = #{createTime}


                and update_time = #{updateTime}

        select
id, user_id, amount, status, description,order_time, is_deleted, create_user, update_user, create_time, update_time
        from `order`

        1 = 1 and is_deleted = 0 

                and id = #{dto.id}


                and user_id = #{dto.userId}


                and amount = #{dto.amount}


                and status = #{dto.status}


                and order_time = #{dto.orderTime}


                and is_deleted = #{dto.isDeleted}


                and create_user = #{dto.createUser}


                and update_user = #{dto.updateUser}


                and create_time = #{dto.createTime}


                and update_time = #{dto.updateTime}


        limit #{limit}

select
id, amount, status,description, order_time,order_type, payment_type
from `order`
where 1 = 1 and is_deleted = 0 and create_user = #{userId}

        and status = #{dto.status}


        and order_type = #{dto.orderType}


        and order_time >= #{dto.orderCreateTime}


        and order_time <= #{dto.orderEndTime}


        and payment_period = #{dto.paymentPeriod}


    and payment_type = #{dto.paymentType}

order by create_time desc
